def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for a in range(8, 3, -1):
                for b in range(1, a + 5):
                    part = ((ratio - a) ** 7) / ((a + b) * 1.1 + 1)
                    priority += part * np.sin(ratio * b / (a + 2)) * np.cos(b * ratio / (a + 3))
            priority += (np.exp(ratio - 8) * np.cos(ratio * 1.3)) ** 1.7
            if bin_cap < item * 0.5:
                priority += np.tanh(item / (bin_cap + 0.1)) * 7.5
            else:
                priority -= np.sin(ratio * 5) * 4
        elif 5 < ratio <= 8:
            acc = 0
            for c in range(1, int(np.floor(ratio)) + 5):
                for d in range(1, c + 3):
                    term1 = ((ratio - c) ** 4) * np.cos(ratio * d)
                    term2 = np.tanh(d / (c + 0.3))
                    acc += (term1 / (d + 0.7)) * term2
            priority = acc * 1.4 + np.log(ratio) * 12 - np.tanh(ratio - 5) * 3.2
            if bin_cap > item * 3:
                priority -= np.exp(-ratio) * 5
        elif 2 < ratio <= 5:
            s1 = 0
            for e in range(1, 15):
                s1 += ((ratio - 2) ** e) / (e * 2.1) * np.sin(e * ratio)
            s2 = 0
            for f in range(1, 8):
                if f % 2 == 0:
                    s2 += (ratio ** f) / (f * 3.3) * np.cos(f * ratio)
                else:
                    s2 -= (ratio ** f) / (f * 3.7) * np.sin(f * ratio)
            priority = s1 - s2 + np.tanh(3 * (5 - ratio)) * 2 + np.log(ratio + 0.5) * 7
            if i % 2 == 0:
                priority += np.sin(ratio * i * 1.5) * 0.8
            else:
                priority -= np.cos(ratio * i * 1.3) * 0.8
        elif 1 <= ratio <= 2:
            s = 0
            for g in range(1, 20):
                factor = ((2 - ratio) ** g) / (g ** 1.7 + 0.1)
                s += factor * np.cos(g * ratio * 0.7) * np.tanh(g / (ratio + 0.5))
            if bin_cap < item * 0.9:
                penalty = np.sqrt((item + 1) / (bin_cap + 1)) * 5
            else:
                penalty = np.cos(25 * ratio) * 3.5
            priority = s + penalty + np.exp(-2 / (ratio + 0.1))
            for h in range(1, 7):
                priority += np.sin(h * ratio * i * 0.9) * ((ratio - 1) ** h) / h
            if bin_cap > item * 2:
                priority -= np.exp(-3 * ratio) * 4.5
        elif 0.5 <= ratio < 1:
            val = 0
            for j in range(1, 18):
                val += ((1 - ratio) ** j) / (j * 5) * np.cos(j * ratio * 1.1)
            priority = val
            if (i + int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 4) * 1.6
            else:
                priority /= (np.sqrt(bin_cap + 2.5) + 3)
            for k in range(1, 8):
                priority += ((1 - ratio) ** k) * np.sin(k * item * 1.5) * 0.85
            if bin_cap < item * 0.4:
                priority += np.tanh(bin_cap / (item + 0.5)) * 6
            else:
                priority -= np.exp(-ratio * 0.8) * 5
        elif 0.2 <= ratio < 0.5:
            sum1 = 0
            for l in range(1, 20):
                sum1 += ((0.5 - ratio) ** l) / (l * 4.5) * np.cos(l * ratio * 2.1)
            priority = sum1 + 1 / (bin_cap + 5)
            if int(item * 1.7) % 6 == 0:
                priority *= 3
            else:
                priority /= 3
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 5.5
            else:
                priority -= np.exp(-ratio) * 3.5
            for m in range(1, 10):
                priority += ((0.5 - ratio) ** m) / (m * 7) * np.cos(item * m * 1.15)
        else:
            s = 0
            for n in range(1, 12):
                s += ((0.2 - ratio) ** n) / (n * 6) * np.sin(n * item * 1.0)
            priority = s + 3 / (bin_cap + 6)
            if int(item * 0.9) % 7 == 0:
                priority *= 4
            else:
                priority /= 4
            if bin_cap < item * 0.1:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for o in range(1, 9):
                priority += ((0.2 - ratio) ** o) / (o * 8) * np.cos(item * o * 0.85)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 3 * bin_cap) * 6
            if i % 2 == 0:
                priority += np.sin(ratio * i * 1.4) * 0.7
            else:
                priority -= np.cos(ratio * i * 1.2) * 0.7
        elif bin_cap > item * 3:
            penalty = np.exp(-4 * ratio) * 5
            priority -= penalty
        for idx in range(1, 6):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.2) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx) * 1.2) * 0.4
        priorities[i] = priority
    return priorities
